import numpy as np

class EMAWeights:
    def __init__(self, initial_weights: dict, decay: float = 0.999, bias_correction: bool = False):
        if not (0 < decay < 1):
            raise ValueError('decay must be in (0, 1)')
        self.decay = decay
        self.bias_correction = bias_correction
        self.shadow = {k: v.copy().astype(np.float64) for k, v in initial_weights.items()}
        self.step = 0

    def update(self, weights: dict):
        self.step += 1
        for k in self.shadow:
            self.shadow[k] = self.decay * self.shadow[k] + (1 - self.decay) * weights[k].astype(np.float64)

    def get_shadow(self) -> dict:
        if self.bias_correction and self.step > 0:
            correction = 1 - self.decay ** self.step
            return {k: v / correction for k, v in self.shadow.items()}
        return {k: v.copy() for k, v in self.shadow.items()}

pytorch_solution_code:
import torch
import torch.nn as nn
import copy

class EMAWeights:
    def __init__(self, model: nn.Module, decay: float = 0.999, bias_correction: bool = False):
        if not (0 < decay < 1):
            raise ValueError('decay must be in (0, 1)')
        self.decay = decay
        self.bias_correction = bias_correction
        self.shadow = copy.deepcopy(model.state_dict())
        for k in self.shadow:
            self.shadow[k] = self.shadow[k].float()
        self.step = 0

    @torch.no_grad()
    def update(self, model: nn.Module):
        self.step += 1
        for k, param in model.state_dict().items():
            self.shadow[k] = self.decay * self.shadow[k] + (1 - self.decay) * param.float()

    def apply_shadow(self, model: nn.Module):
        shadow = self.get_shadow()
        model.load_state_dict(shadow)

    def get_shadow(self) -> dict:
        if self.bias_correction and self.step > 0:
            correction = 1 - self.decay ** self.step
            return {k: v / correction for k, v in self.shadow.items()}
        return {k: v.clone() for k, v in self.shadow.items()}
